template.script:
(function() {
    const container = document.getElementById('justifi-payment-container');
    if (!container) return;

    // Hide Odoo's default submit button
    setTimeout(function() {
        const submitBtns = document.querySelectorAll('.o_payment_submit_button, button[name="o_payment_submit_button"]');
        submitBtns.forEach(function(btn) { btn.style.display = 'none'; });
    }, 100);

    const checkoutId = container.dataset.checkoutId || '';
    const apiUrl = container.dataset.apiUrl || '/payment/justifi/complete';
    const paymentAmount = container.dataset.amount || '';
    const currencyId = container.dataset.currencyId || '';
    const partnerId = container.dataset.partnerId || '';
    const providerId = container.dataset.providerId || '';
    const paymentMethods = container.dataset.paymentMethods || 'both';

    const loadingEl = document.getElementById('justifi-loading');
    const errorEl = document.getElementById('justifi-error');
    const wrapperEl = document.getElementById('justifi-checkout-wrapper');
    const checkoutEl = document.getElementById('justifi-modular-checkout');
    const submitBtnEl = document.getElementById('justifi-submit-btn');

    function showError(message) {
        loadingEl.style.display = 'none';
        if (wrapperEl) wrapperEl.style.display = 'none';
        errorEl.textContent = message;
        errorEl.style.display = 'block';
    }

    function redirectToComplete(detail) {
        console.log('=== JUSTIFI CHECKOUT COMPLETE ===');
        console.log('Event detail:', detail);

        // Extract payment_id if available
        let paymentId = '';
        if (detail) {
            if (detail.checkout && detail.checkout.successful_payment_id) {
                paymentId = detail.checkout.successful_payment_id;
            } else if (detail.successful_payment_id) {
                paymentId = detail.successful_payment_id;
            }
        }

        console.log('Payment ID:', paymentId);
        console.log('Checkout ID:', checkoutId);

        const fields = {
            'checkout_id': checkoutId,
            'payment_id': paymentId,
            'amount': paymentAmount,
            'currency_id': currencyId,
            'partner_id': partnerId,
            'provider_id': providerId
        };
        console.log('Submitting:', fields);

        const form = document.createElement('form');
        form.method = 'POST';
        form.action = apiUrl;
        for (const [key, value] of Object.entries(fields)) {
            const input = document.createElement('input');
            input.type = 'hidden';
            input.name = key;
            input.value = value || '';
            form.appendChild(input);
        }
        document.body.appendChild(form);
        form.submit();
    }

    if (!checkoutId || !checkoutEl) {
        showError('Payment configuration error. Please contact support.');
        return;
    }

    // Listen for submit-event (checkout completed by component)
    checkoutEl.addEventListener('submit-event', function(event) {
        console.log('JustiFi modular checkout submit-event:', event.detail);
        redirectToComplete(event.detail);
    });

    // Listen for error-event
    checkoutEl.addEventListener('error-event', function(event) {
        console.log('JustiFi modular checkout error-event:', event.detail);
        const errorMsg = event.detail?.message || event.detail?.error || 'Payment failed. Please try again.';
        showError(errorMsg);
        submitBtnEl.disabled = false;
        submitBtnEl.textContent = 'Pay Now';
    });

    // Payment method tab toggling (card/bank)
    if (paymentMethods === 'both') {
        const tabs = container.querySelectorAll('.jf-payment-tab');
        const cardForm = document.getElementById('jf-card-form-container');
        const bankForm = document.getElementById('jf-bank-form-container');

        tabs.forEach(function(tab) {
            tab.addEventListener('click', function() {
                const method = tab.getAttribute('data-payment-method');

                // Update tab selection
                tabs.forEach(function(t) { t.classList.remove('selected'); });
                tab.classList.add('selected');

                // Toggle form visibility
                if (method === 'card') {
                    if (cardForm) cardForm.style.display = 'block';
                    if (bankForm) bankForm.style.display = 'none';
                } else if (method === 'bank') {
                    if (cardForm) cardForm.style.display = 'none';
                    if (bankForm) bankForm.style.display = 'block';
                }
            });
        });
    }

    // Wait for component to be defined, then show it
    customElements.whenDefined('justifi-modular-checkout').then(function() {
        console.log('justifi-modular-checkout is available');
        loadingEl.style.display = 'none';
        wrapperEl.style.display = 'block';
    }).catch(function(err) {
        console.error('Failed to load justifi-modular-checkout:', err);
        showError('Failed to load payment form. Please refresh the page.');
    });

    // Handle submit button click
    submitBtnEl.addEventListener('click', function(e) {
        e.preventDefault();
        e.stopPropagation();
        submitBtnEl.disabled = true;
        submitBtnEl.textContent = 'Processing...';
        console.log('Calling submitCheckout()');
        if (checkoutEl && typeof checkoutEl.submitCheckout === 'function') {
            checkoutEl.submitCheckout();
        } else {
            console.error('submitCheckout not available');
            showError('Payment form not ready. Please refresh and try again.');
        }
    });
})();
